   291	        private async Task OnChangeAsync(InputFileChangeEventArgs args)
   292	        {
   293	            _numberOfActiveFileInputs++;
   294	
   295	            if (GetDisabledState())
   296	                return;
   297	
   298	            await ProcessFileChangeAsync(args);
   299	        }
   300	
   301	        private async Task ProcessFileChangeAsync(InputFileChangeEventArgs args)
   302	        {
   303	            T? value;
   304	
   305	            if (args.FileCount > MaximumFileCount)
   306	            {
   307	                // Notify the consumer about the exceeded file count
   308	                _validationErrors.Add(Localizer[LanguageResource.MudFileUpload_MaximumFileCountExceeded, args.FileCount, MaximumFileCount]);
   309	                await NotifyValueChangedAsync(default); // Reset the value to indicate no valid files were processed
   310	                return;
   311	            }
   312	
   313	            if (typeof(T) == typeof(IReadOnlyList<IBrowserFile>))
   314	            {
   315	                value = (T?)(object)ProcessMultipleFiles(args.GetMultipleFiles(MaximumFileCount));
   316	            }
   317	            else if (typeof(T) == typeof(IBrowserFile))
   318	            {
   319	                value = (T?)ProcessSingleFile(args.FileCount == 1 ? args.File : null);
   320	            }
   321	            else
   322	            {
   323	                return;
   324	            }
   325	
   326	            await NotifyValueChangedAsync(value);
   327	
   328	            if (!ErrorState.Value || !SuppressOnChangeWhenInvalid)
   329	                await OnFilesChanged.InvokeAsync(args);
   330	        }
   331	
   332	        private IReadOnlyList<IBrowserFile> ProcessMultipleFiles(IReadOnlyCollection<IBrowserFile> files)
   333	        {
   334	            var validFiles = new List<IBrowserFile>();
   335	
   336	            foreach (var file in files)
   337	            {
   338	                if (MaxFileSize.HasValue && file.Size > MaxFileSize.Value)
   339	                {
   340	                    _validationErrors.Add(Localizer[LanguageResource.MudFileUpload_FileSizeError, file.Name, MaxFileSize.Value.ToString()]);
   341	                }
   342	                else
   343	                {
   344	                    validFiles.Add(file);
   345	                }
   346	            }
   347	
   348	            var newFiles = validFiles.AsReadOnly();
   349	
   350	            if (AppendMultipleFiles && _filesState.Value is IReadOnlyList<IBrowserFile> oldFiles)
   351	                return oldFiles.Concat(newFiles).ToList().AsReadOnly();
   352	
   353	            return newFiles;
   354	        }
   355	
   356	        private IBrowserFile? ProcessSingleFile(IBrowserFile? file)
   357	        {
   358	            if (file == null)
   359	                return null;
   360	
   361	            if (MaxFileSize.HasValue && file.Size > MaxFileSize.Value)
   362	            {
   363	                _validationErrors.Add(Localizer[LanguageResource.MudFileUpload_FileSizeError, file.Name, MaxFileSize.Value.ToString()]);
   364	                return null;
   365	            }
   366	
   367	            return file;
   368	        }
