   370	        protected override void OnInitialized()
   371	        {
   372	            if (!(typeof(T) == typeof(IReadOnlyList<IBrowserFile>) || typeof(T) == typeof(IBrowserFile)))
   373	            {
   374	                Logger.LogWarning("T must be of type {type1} or {type2}", typeof(IReadOnlyList<IBrowserFile>), typeof(IBrowserFile));
   375	            }
   376	
   377	            base.OnInitialized();
   378	        }
