   380	        private async Task NotifyValueChangedAsync(T? value)
   381	        {
   382	            Touched = true;
   383	            await _filesState.SetValueAsync(value);
   384	            await BeginValidateAsync();
   385	            FieldChanged(value);
   386	        }
