   403	        {
   404	            await base.ValidateValue();
   405	
   406	            ValidationErrors = [.. ValidationErrors, .. _validationErrors];
   407	            await ErrorState.SetValueAsync(ValidationErrors.Count > 0);
   408	            await ErrorTextState.SetValueAsync(ValidationErrors.FirstOrDefault());
   409	        }
