     5	// noinspection JSUnusedGlobalSymbols
     6	/**
     7	 * Programmatic file picker trigger for the file upload component.
     8	 * Prefers `showPicker()` and falls back to `click()` for broader browser support.
     9	 */
    10	class MudFileUpload {
    11	    /**
    12	     * Opens the file picker for the target input element.
    13	     */
    14	    openFilePicker (id) {
    15	        const element = document.getElementById(id);
    16	
    17	        if (!element) {
    18	            return;
    19	        }
    20	
    21	        try {
    22	            // Prefer showPicker when available because it follows native picker semantics more consistently.
    23	            element.showPicker();
    24	        } catch (_) {
    25	            // click() keeps older engines working when showPicker is unavailable/restricted.
    26	            element.click();
    27	        }
    28	    }
    29	}
    30	
    31	window.mudFileUpload = new MudFileUpload();
