        /// </summary>
        /// <remarks>
        /// Defaults to <c>null</c> (no limit).  Files exceeding this limit are rejected and a validation error is added.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FileUpload.Behavior)]
        public long? MaxFileSize { get; set; }

