        /// </summary>
        /// <remarks>
        /// Defaults to <c>false</c>.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FileUpload.Behavior)]
        public bool Disabled { get; set; }

        [CascadingParameter(Name = "ParentDisabled")]
        private bool ParentDisabled { get; set; }

        [CascadingParameter(Name = "ParentReadOnly")]
        private bool ParentReadOnly { get; set; }

        /// <summary>
        /// Returns the filenames for the selected files.
        /// </summary>
        /// <remarks>
        /// When <c>T</c> is <see cref="IBrowserFile" />, a single filename is returned.<br />
        /// When <c>T</c> is <see cref="IReadOnlyList{IBrowserFile}">IReadOnlyList&lt;IBrowserFile&gt;</see>, multiple filenames are returned.
        /// </remarks>
        public IReadOnlyList<string> GetFilenames()
        {
            if (EqualityComparer<T>.Default.Equals(_filesState.Value, default))
            {
                return [];
            }
            return _filesState.Value switch
            {
                IBrowserFile singleFile => [singleFile.Name],
                IReadOnlyList<IBrowserFile> fileList => fileList.Select(f => f.Name).ToList(),
                _ => []
            };
        }

        protected bool GetDisabledState() => Disabled || ParentDisabled || ParentReadOnly;

        private Task OnDropAsync(DragEventArgs args) => OnDragResetAsync(args, "ondrop");

        private Task OnDragLeaveAsync(DragEventArgs args) => OnDragResetAsync(args, "ondragleave");

        private Task OnDragEndAsync(DragEventArgs args) => OnDragResetAsync(args, "ondragend");

        private async Task OnDragResetAsync(DragEventArgs args, string eventName)
        {
            await _draggingState.SetValueAsync(false);
            await InvokeUserDragEventAsync(args, eventName);
        }

        private async Task InvokeUserDragEventAsync(DragEventArgs args, string eventName)
        {
            if (!TryGetUserDragEvent(eventName, out var callback) || callback is null)
            {
                return;
            }

            switch (callback)
            {
                case EventCallback<DragEventArgs> eventCallback when eventCallback.HasDelegate:
                    await eventCallback.InvokeAsync(args);
                    break;
                case EventCallback eventCallback when eventCallback.HasDelegate:
                    await eventCallback.InvokeAsync(args);
                    break;
                case Func<DragEventArgs, Task> func:
                    await func(args);
                    break;
                case Func<Task> func:
                    await func();
                    break;
                case Action<DragEventArgs> action:
                    action(args);
                    break;
                case Action action:
                    action();
                    break;
            }
        }

        private Task OnDragAreaClickAsync()
        {
            if (GetDisabledState())
            {
                return Task.CompletedTask;
            }

            return OpenFilePickerAsync();
        }

        private Task OnDragEnterAsync()
        {
            if (GetDisabledState())
            {
                return Task.CompletedTask;
            }

            return _draggingState.SetValueAsync(true);
        }

        private Task OnFileChipCloseAsync(string filename)
        {
            if (GetDisabledState())
            {
                return Task.CompletedTask;
            }

            return RemoveFileAsync(filename);
        }

        private int _numberOfActiveFileInputs = 1;
